local function check_auth(token)
    -- Your authentication logic here
    local user_roles = {"admin", "editor"}

    if not token or not table.find(user_roles, ngx.var.role) then
        ngx.exit(ngx.HTTP_FORBIDDEN)
        return false
    end

    local uri = ngx.var.uri
    local admin_endpoints = {"/admin", "/api"}

    if next(table.filter({token, uri}, function(val) return table.find(admin_endpoints, val) end)) then
        -- Skip permission checks for the specified endpoints
        return true
    else
        return false
    end
end

local function main()
    local token = ngx.var.http_token -- Assuming you have a header named 'http_token'

    if check_auth(token) then
        -- Continue processing the request
        return ngx.next()
    else
        ngx.exit(ngx.HTTP_FORBIDDEN)
    end
end

